    "description": "Build a directions request URL with optional route constraints, timing, transit preferences, waypoint lists, units, and alternative-route flags serialized into query parameters.",
    "cases": [
        {
            "input": {
                "api_key": "MY_API_KEY",
                "endpoint": "directions",
                "origin": "Toronto",
                "destination": "Montreal",
                "avoid": "tolls"
            },
            "expected_output": "url=https://maps.googleapis.com/maps/api/directions/json?origin=Toronto&destination=Montreal&avoid=tolls&key=MY_API_KEY\n"
        },
        {
            "input": {
                "api_key": "MY_API_KEY",
                "endpoint": "directions",
                "origin": "Toronto",
                "destination": "Montreal",
                "avoid": "highways"
