            "expected_output": "url=https://maps.googleapis.com/maps/api/directions/json?origin=Toronto&destination=Montreal&avoid=highways&key=MY_API_KEY\n"
        },
        {
            "input": {
                "api_key": "MY_API_KEY",
                "endpoint": "directions",
